2376   const Loop *SrcLoop, *DstLoop;
2377 
2378   LLVM_DEBUG(dbgs() << "    src = " << *Src << "\n");
2379   LLVM_DEBUG(dbgs() << "    dst = " << *Dst << "\n");
2380   const SCEVAddRecExpr *SrcAddRec = dyn_cast<SCEVAddRecExpr>(Src);
2381   const SCEVAddRecExpr *DstAddRec = dyn_cast<SCEVAddRecExpr>(Dst);
