1565 ceilingOfQuotient(const OverflowSafeSignedAPInt &OA,
1566                   const OverflowSafeSignedAPInt &OB) {
1567   if (!OA || !OB)
1568     return OverflowSafeSignedAPInt();
1569 
1570   APInt A = *OA;
