1708   APInt TX = X * TC;
1709   APInt TY = Y * TC;
1710   LLVM_DEBUG(dbgs() << "\t    TC = " << TC << "\n");
1711   LLVM_DEBUG(dbgs() << "\t    TX = " << TX << "\n");
1712   LLVM_DEBUG(dbgs() << "\t    TY = " << TY << "\n");
