1739   SmallVector<APInt, 2> TLVec = CreateVec(TL0, TL1);
1740   SmallVector<APInt, 2> TUVec = CreateVec(TU0, TU1);
1741 
1742   LLVM_DEBUG(dbgs() << "\t    TA = " << TA << "\n");
1743   LLVM_DEBUG(dbgs() << "\t    TB = " << TB << "\n");
