2411 /// Given a SCEVMulExpr, returns its first operand if its first operand is a
2412 /// constant and the product doesn't overflow in a signed sense. Otherwise,
2413 /// returns std::nullopt. For example, given (10 * X * Y)<nsw>, it returns 10.
2414 /// Notably, if it doesn't have nsw, the multiplication may overflow, and if
2415 /// so, it may not a multiple of 10.
2416 static std::optional<APInt> getConstantCoefficient(const SCEV *Expr) {
2417   if (const auto *Constant = dyn_cast<SCEVConstant>(Expr))
2418     return Constant->getAPInt();
2419   if (const auto *Product = dyn_cast<SCEVMulExpr>(Expr))
2420     if (const auto *Constant = dyn_cast<SCEVConstant>(Product->getOperand(0)))
2421       if (Product->hasNoSignedWrap())
2422         return Constant->getAPInt();
2423   return std::nullopt;
2424 }
