2512   // we can't quit the loop just because the GCD == 1.
2513   Coefficients = Dst;
2514   while (const SCEVAddRecExpr *AddRec =
2515              dyn_cast<SCEVAddRecExpr>(Coefficients)) {
2516     const SCEV *Coeff = AddRec->getStepRecurrence(*SE);
2517     // If the coefficient is the product of a constant and other stuff,
2518     // we can use the constant in the GCD computation.
2519     std::optional<APInt> ConstCoeff = getConstantCoefficient(Coeff);
2520     if (!ConstCoeff)
2521       return false;
2522     RunningGCD = APIntOps::GreatestCommonDivisor(RunningGCD, ConstCoeff->abs());
2523     Coefficients = AddRec->getStart();
2524   }
2525   const SCEV *DstConst = Coefficients;
2526 
2527   APInt ExtraGCD = APInt::getZero(BitWidth);
2528   const SCEV *Delta = minusSCEVNoSignedOverflow(DstConst, SrcConst, *SE);
2529   if (!Delta)
2530     return false;
2531   LLVM_DEBUG(dbgs() << "    Delta = " << *Delta << "\n");
2532   const SCEVConstant *Constant = dyn_cast<SCEVConstant>(Delta);
2533   if (!Constant)
2534     return false;
2535   APInt ConstDelta = cast<SCEVConstant>(Constant)->getAPInt();
2536   LLVM_DEBUG(dbgs() << "    ConstDelta = " << ConstDelta << "\n");
2537   if (ConstDelta == 0)
2538     return false;
2539   LLVM_DEBUG(dbgs() << "    RunningGCD = " << RunningGCD << "\n");
2540   APInt Remainder = ConstDelta.srem(RunningGCD);
2541   if (Remainder != 0) {
2542     ++GCDindependence;
2543     return true;
2544   }
2545 
2546   // Try to disprove equal directions.
2547   // For example, given a subscript pair [3*i + 2*j] and [i' + 2*j' - 1],
2548   // the code above can't disprove the dependence because the GCD = 1.
2549   // So we consider what happen if i = i' and what happens if j = j'.
2550   // If i = i', we can simplify the subscript to [2*i + 2*j] and [2*j' - 1],
2551   // which is infeasible, so we can disallow the = direction for the i level.
2552   // Setting j = j' doesn't help matters, so we end up with a direction vector
2553   // of [<>, *]
2554   //
2555   // Given A[5*i + 10*j*M + 9*M*N] and A[15*i + 20*j*M - 21*N*M + 5],
2556   // we need to remember that the constant part is 5 and the RunningGCD should
2557   // be initialized to ExtraGCD = 30.
2558   LLVM_DEBUG(dbgs() << "    ExtraGCD = " << ExtraGCD << '\n');
2559 
2560   bool Improved = false;
2561   Coefficients = Src;
2562   while (const SCEVAddRecExpr *AddRec =
2563              dyn_cast<SCEVAddRecExpr>(Coefficients)) {
2564     Coefficients = AddRec->getStart();
2565     const Loop *CurLoop = AddRec->getLoop();
2566     RunningGCD = ExtraGCD;
2567     const SCEV *SrcCoeff = AddRec->getStepRecurrence(*SE);
2568     const SCEV *DstCoeff = SE->getMinusSCEV(SrcCoeff, SrcCoeff);
2569 
2570     if (!accumulateCoefficientsGCD(Src, CurLoop, SrcCoeff, RunningGCD) ||
2571         !accumulateCoefficientsGCD(Dst, CurLoop, DstCoeff, RunningGCD))
2572       return false;
2573 
2574     Delta = SE->getMinusSCEV(SrcCoeff, DstCoeff);
2575     // If the coefficient is the product of a constant and other stuff,
2576     // we can use the constant in the GCD computation.
2577     std::optional<APInt> ConstCoeff = getConstantCoefficient(Delta);
2578     if (!ConstCoeff)
2579       // The difference of the two coefficients might not be a product
2580       // or constant, in which case we give up on this direction.
2581       continue;
2582     RunningGCD = APIntOps::GreatestCommonDivisor(RunningGCD, ConstCoeff->abs());
2583     LLVM_DEBUG(dbgs() << "\tRunningGCD = " << RunningGCD << "\n");
2584     if (RunningGCD != 0) {
2585       Remainder = ConstDelta.srem(RunningGCD);
2586       LLVM_DEBUG(dbgs() << "\tRemainder = " << Remainder << "\n");
2587       if (Remainder != 0) {
2588         unsigned Level = mapSrcLoop(CurLoop);
2589         Result.DV[Level - 1].Direction &= ~Dependence::DVEntry::EQ;
2590         Improved = true;
2591       }
2592     }
2593   }
2594   if (Improved)
2595     ++GCDsuccesses;
2596   LLVM_DEBUG(dbgs() << "all done\n");
2597   return false;
2598 }
