2601 // banerjeeMIVtest -
2602 // Use Banerjee's Inequalities to test an MIV subscript pair.
2603 // (Wolfe, in the race-car book, calls this the Extreme Value Test.)
2604 // Generally follows the discussion in Section 2.5.2 of
2605 //
2606 //    Optimizing Supercompilers for Supercomputers
2607 //    Michael Wolfe
2608 //
2609 // The inequalities given on page 25 are simplified in that loops are
2610 // normalized so that the lower bound is always 0 and the stride is always 1.
2611 // For example, Wolfe gives
2612 //
2613 //     LB^<_k = (A^-_k - B_k)^- (U_k - L_k - N_k) + (A_k - B_k)L_k - B_k N_k
2614 //
2615 // where A_k is the coefficient of the kth index in the source subscript,
2616 // B_k is the coefficient of the kth index in the destination subscript,
2617 // U_k is the upper bound of the kth index, L_k is the lower bound of the Kth
2618 // index, and N_k is the stride of the kth index. Since all loops are normalized
2619 // by the SCEV package, N_k = 1 and L_k = 0, allowing us to simplify the
2620 // equation to
2621 //
2622 //     LB^<_k = (A^-_k - B_k)^- (U_k - 0 - 1) + (A_k - B_k)0 - B_k 1
2623 //            = (A^-_k - B_k)^- (U_k - 1)  - B_k
2624 //
2625 // Similar simplifications are possible for the other equations.
2626 //
2627 // When we can't determine the number of iterations for a loop,
2628 // we use NULL as an indicator for the worst case, infinity.
2629 // When computing the upper bound, NULL denotes +inf;
2630 // for the lower bound, NULL denotes -inf.
2631 //
2632 // Return true if dependence disproved.
2633 bool DependenceInfo::banerjeeMIVtest(const SCEV *Src, const SCEV *Dst,
2634                                      const SmallBitVector &Loops,
2635                                      FullDependence &Result) const {
2636   if (!isDependenceTestEnabled(DependenceTestType::BanerjeeMIV))
2637     return false;
2638 
2639   LLVM_DEBUG(dbgs() << "starting Banerjee\n");
2640   ++BanerjeeApplications;
2641   LLVM_DEBUG(dbgs() << "    Src = " << *Src << '\n');
2642   const SCEV *A0;
2643   CoefficientInfo *A = collectCoeffInfo(Src, true, A0);
2644   LLVM_DEBUG(dbgs() << "    Dst = " << *Dst << '\n');
2645   const SCEV *B0;
2646   CoefficientInfo *B = collectCoeffInfo(Dst, false, B0);
2647   BoundInfo *Bound = new BoundInfo[MaxLevels + 1];
2648   const SCEV *Delta = SE->getMinusSCEV(B0, A0);
2649   LLVM_DEBUG(dbgs() << "\tDelta = " << *Delta << '\n');
2650 
2651   // Compute bounds for all the * directions.
2652   LLVM_DEBUG(dbgs() << "\tBounds[*]\n");
2653   for (unsigned K = 1; K <= MaxLevels; ++K) {
2654     Bound[K].Iterations = A[K].Iterations ? A[K].Iterations : B[K].Iterations;
2655     Bound[K].Direction = Dependence::DVEntry::ALL;
2656     Bound[K].DirSet = Dependence::DVEntry::NONE;
2657     findBoundsALL(A, B, Bound, K);
2658 #ifndef NDEBUG
2659     LLVM_DEBUG(dbgs() << "\t    " << K << '\t');
2660     if (Bound[K].Lower[Dependence::DVEntry::ALL])
2661       LLVM_DEBUG(dbgs() << *Bound[K].Lower[Dependence::DVEntry::ALL] << '\t');
2662     else
2663       LLVM_DEBUG(dbgs() << "-inf\t");
2664     if (Bound[K].Upper[Dependence::DVEntry::ALL])
2665       LLVM_DEBUG(dbgs() << *Bound[K].Upper[Dependence::DVEntry::ALL] << '\n');
2666     else
2667       LLVM_DEBUG(dbgs() << "+inf\n");
2668 #endif
2669   }
2670 
2671   // Test the *, *, *, ... case.
2672   bool Disproved = false;
2673   if (testBounds(Dependence::DVEntry::ALL, 0, Bound, Delta)) {
2674     // Explore the direction vector hierarchy.
2675     unsigned DepthExpanded = 0;
2676     unsigned NewDeps =
2677         exploreDirections(1, A, B, Bound, Loops, DepthExpanded, Delta);
2678     if (NewDeps > 0) {
2679       bool Improved = false;
2680       for (unsigned K = 1; K <= CommonLevels; ++K) {
2681         if (Loops[K]) {
2682           unsigned Old = Result.DV[K - 1].Direction;
2683           Result.DV[K - 1].Direction = Old & Bound[K].DirSet;
2684           Improved |= Old != Result.DV[K - 1].Direction;
2685           if (!Result.DV[K - 1].Direction) {
2686             Improved = false;
2687             Disproved = true;
2688             break;
2689           }
2690         }
2691       }
2692       if (Improved)
2693         ++BanerjeeSuccesses;
2694     } else {
2695       ++BanerjeeIndependence;
2696       Disproved = true;
2697     }
2698   } else {
2699     ++BanerjeeIndependence;
2700     Disproved = true;
2701   }
2702   delete[] Bound;
2703   delete[] A;
2704   delete[] B;
2705   return Disproved;
2706 }
